INSERT INTO value_tiers (tier_id, tier_name, threshold_type, threshold_value, description, benefits) VALUES ('T-01', 'Platinum', 'quartile', 0.75, 'VIP customers generating the highest lifetime revenue.', 'Free express shipping | Dedicated support | Early sale access | Exclusive coupons') ON CONFLICT DO NOTHING;
INSERT INTO value_tiers (tier_id, tier_name, threshold_type, threshold_value, description, benefits) VALUES ('T-02', 'Gold', 'quartile', 0.5, 'High-value customers with strong and consistent purchasing behaviour.', 'Free standard shipping | Priority support | Monthly promo emails') ON CONFLICT DO NOTHING;
INSERT INTO value_tiers (tier_id, tier_name, threshold_type, threshold_value, description, benefits) VALUES ('T-03', 'Silver', 'quartile', 0.25, 'Mid-tier customers with growth potential.', 'Occasional discount vouchers | Birthday offer | Category-specific promos') ON CONFLICT DO NOTHING;
INSERT INTO value_tiers (tier_id, tier_name, threshold_type, threshold_value, description, benefits) VALUES ('T-04', 'Bronze', 'quartile', 0, 'Low-spend or newly acquired customers requiring nurturing.', 'Welcome offer | Free first delivery | Basic newsletter') ON CONFLICT DO NOTHING;
INSERT INTO business_segments (segment_id, segment_name, description, criteria, recommended_focus) VALUES ('SEG-001', 'Champions', 'Highest RFM scores — bought recently, buy often, spend the most.', 'rfm_total_score >= 12', 'Reward & retain. Offer loyalty perks and early access deals.') ON CONFLICT DO NOTHING;
INSERT INTO business_segments (segment_id, segment_name, description, criteria, recommended_focus) VALUES ('SEG-002', 'Loyal Customers', 'Regular buyers. Spend well. Respond to promotions.', 'frequency_score >= 4 and monetary_score >= 3', 'Upsell premium products. Invite to Walmart+ membership.') ON CONFLICT DO NOTHING;
INSERT INTO business_segments (segment_id, segment_name, description, criteria, recommended_focus) VALUES ('SEG-003', 'Potential Loyalists', 'Recent customers with medium frequency and spend.', 'recency_score >= 4 and frequency_score >= 2 and frequency_score <= 3', 'Nurture with personalised recommendations and bundles.') ON CONFLICT DO NOTHING;
INSERT INTO business_segments (segment_id, segment_name, description, criteria, recommended_focus) VALUES ('SEG-004', 'At-Risk Customers', 'Were good customers. Haven''t bought recently.', 'recency_score <= 2 and frequency_score >= 3', 'Send win-back email. Offer time-limited discount.') ON CONFLICT DO NOTHING;
INSERT INTO business_segments (segment_id, segment_name, description, criteria, recommended_focus) VALUES ('SEG-005', 'New Customers', 'Bought recently but only once or twice.', 'recency_score >= 4 and frequency_score <= 2', 'Onboarding flow. Show category breadth. Free shipping offer.') ON CONFLICT DO NOTHING;
INSERT INTO business_segments (segment_id, segment_name, description, criteria, recommended_focus) VALUES ('SEG-006', 'Hibernating', 'Low recency, low frequency, low monetary.', 'rfm_total_score <= 5', 'Low-cost reactivation email. Consider removing from campaigns.') ON CONFLICT DO NOTHING;
INSERT INTO business_segments (segment_id, segment_name, description, criteria, recommended_focus) VALUES ('SEG-007', 'Lost', 'Longest inactive. No recent engagement.', 'days_since_last_order > 180 and recency_score == 1', 'Final win-back attempt then suppress from active list.') ON CONFLICT DO NOTHING;
